#!/usr/bin/env python3
import os,sys,json,time,subprocess,random
def psql(q,t=30):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR:"+r.stderr.strip()[:90])
out={"kind":"srccensus","ts":int(time.time())}
try:
    out["catalog_total"]=psql("SELECT count(*) FROM atlas.source_catalog")
    out["catalog_by_state"]=psql("SELECT state, count(*) FROM atlas.source_catalog GROUP BY state ORDER BY count(*) DESC")
    out["wired"]=psql("SELECT count(*) FROM atlas.source_catalog WHERE state='WIRED'")
    out["approved_not_wired"]=psql("SELECT count(*) FROM atlas.source_catalog WHERE state='APPROVED'")
    # actually ingesting = distinct source_code present in source_record
    has_sr=psql("SELECT count(*) FROM information_schema.tables WHERE table_schema='atlas' AND table_name='source_record'")
    if has_sr=='1':
        out["sources_with_rows"]=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record")
        out["socrata_sources_with_rows"]=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record WHERE source_code LIKE 'socrata_%'")
        out["rows_ingested_total"]=psql("SELECT count(*) FROM atlas.source_record")
        out["ingested_last_24h"]=psql("SELECT count(*) FROM atlas.source_record WHERE created_at > now()-interval '24 hours'") if psql("SELECT count(*) FROM information_schema.columns WHERE table_schema='atlas' AND table_name='source_record' AND column_name='created_at'")=='1' else 'no_ts'
        out["top_sources"]=psql("SELECT source_code||':'||c FROM (SELECT source_code, count(*) c FROM atlas.source_record GROUP BY source_code ORDER BY c DESC LIMIT 8) x")
    else:
        out["sources_with_rows"]="no source_record table"
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/srccensus.json"%repo
    if tok:
        for _ in range(12):
            try:
                sha=None
                try:
                    rq=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(rq,timeout=15)).get("sha")
                except Exception: sha=None
                body={"message":"srccensus","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
                if sha: body["sha"]=sha
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=18); break
            except Exception: time.sleep(0.5+random.random()*2)
except Exception: pass
sys.exit(0)
